/* data+ :: content/quiz1.js — DA0-002 Domain 1 question bank (100 items). */
window.DATAPLUS = window.DATAPLUS || {}; DATAPLUS.questions = DATAPLUS.questions || [];
DATAPLUS.questions.push(
{ id:"D1-001", domain:1, obj:"1.1", diff:"easy", q:"An analyst must store customer records where every row has the same fixed set of columns and relationships are enforced between tables. Which database type BEST fits this requirement?", options:["A relational (SQL) database","A key-value store","A graph database","A document store"], answer:0, explain:"<strong>A relational (SQL) database</strong> organizes data into tables of rows and columns with a fixed schema and enforces relationships through primary and foreign keys, which matches structured customer records.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A key-value store</b>: a key-value store holds opaque values addressed by a key and does not enforce table relationships or a fixed column schema.</span><span class='qd'><b>A graph database</b>: a graph database is optimized for traversing connections between nodes, not for tabular records with uniform columns.</span><span class='qd'><b>A document store</b>: a document store keeps flexible, schema-less documents and is a non-relational choice that does not enforce fixed columns.</span>" },
{ id:"D1-002", domain:1, obj:"1.1", diff:"easy", q:"A development team needs to store JSON documents whose fields vary from one record to the next without redesigning a schema. Which database type is MOST appropriate?", options:["A relational database","A document (NoSQL) database","A columnar data warehouse","A flat CSV file"], answer:1, explain:"<strong>A document (NoSQL) database</strong> such as MongoDB stores semi-structured JSON documents that can have differing fields per record, so it handles varying structure without schema redesign.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A relational database</b>: a relational database requires a defined column schema, so varying fields per record would force frequent schema changes.</span><span class='qd'><b>A columnar data warehouse</b>: a columnar warehouse is tuned for analytical queries over structured columns, not flexible per-record JSON.</span><span class='qd'><b>A flat CSV file</b>: a CSV file is a fixed two-dimensional grid and cannot naturally represent nested or varying JSON fields.</span>" },
{ id:"D1-003", domain:1, obj:"1.1", diff:"medium", q:"A database administrator must guarantee that a funds-transfer transaction either completes fully or not at all, even if the server crashes mid-operation. Which ACID property MOST directly provides this guarantee?", options:["Consistency","Isolation","Atomicity","Durability"], answer:2, explain:"<strong>Atomicity</strong> ensures a transaction is all-or-nothing, so a funds transfer either commits completely or rolls back entirely if interrupted.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Consistency</b>: consistency keeps the database in a valid state against its rules but does not by itself make a transaction all-or-nothing.</span><span class='qd'><b>Isolation</b>: isolation prevents concurrent transactions from interfering, which is a different concern than completing one transaction fully.</span><span class='qd'><b>Durability</b>: durability guarantees committed results survive a crash, but the all-or-nothing behavior during the operation is atomicity.</span>" },
{ id:"D1-004", domain:1, obj:"1.1", diff:"medium", q:"After a transaction commits, a power failure occurs. The committed changes are still present when the database restarts. Which ACID property ensures this?", options:["Consistency","Atomicity","Isolation","Durability"], answer:3, explain:"<strong>Durability</strong> guarantees that once a transaction is committed, its changes are permanently saved and survive a crash or power loss.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Atomicity</b>: atomicity ensures a transaction completes fully or not at all, but it does not guarantee committed data survives a crash.</span><span class='qd'><b>Isolation</b>: isolation governs how concurrent transactions are kept separate, not whether committed data persists.</span><span class='qd'><b>Consistency</b>: consistency keeps data valid against constraints but says nothing about surviving a power failure.</span>" },
{ id:"D1-005", domain:1, obj:"1.1", diff:"medium", q:"An analyst notices the same customer address is duplicated across many order rows, causing update anomalies. Which database technique is designed to reduce this redundancy?", options:["Normalization","Denormalization","Indexing","Partitioning"], answer:0, explain:"<strong>Normalization</strong> organizes data into related tables to eliminate redundancy and update anomalies, so a customer address would live in one place and be referenced by a key.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Denormalization</b>: denormalization deliberately adds redundancy to speed reads, which is the opposite of removing duplication.</span><span class='qd'><b>Indexing</b>: indexing speeds lookups but does not remove duplicated data values across rows.</span><span class='qd'><b>Partitioning</b>: partitioning splits a table into segments for performance and does not address repeated values.</span>" },
{ id:"D1-006", domain:1, obj:"1.1", diff:"hard", q:"A reporting data warehouse intentionally stores a flattened sales table with repeated dimension values to make analytical queries faster. This deliberate design choice is BEST described as:", options:["Normalization to third normal form","Denormalization","Referential integrity enforcement","Atomic transactions"], answer:1, explain:"<strong>Denormalization</strong> deliberately introduces redundancy, such as repeating dimension values in a flat table, to reduce joins and accelerate read-heavy analytical queries.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Normalization to third normal form</b>: normalization removes redundancy and would split the flattened table apart, slowing analytical reads.</span><span class='qd'><b>Referential integrity enforcement</b>: referential integrity ensures foreign keys match valid parents and is unrelated to flattening for speed.</span><span class='qd'><b>Atomic transactions</b>: atomicity concerns all-or-nothing writes, not the storage layout for fast reads.</span>" },
{ id:"D1-007", domain:1, obj:"1.1", diff:"easy", q:"A column that uniquely identifies each row in a table and cannot contain null values is known as the:", options:["Foreign key","Composite index","Primary key","Surrogate column"], answer:2, explain:"<strong>Primary key</strong> uniquely identifies each row and must be unique and non-null, making it the canonical row identifier.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Foreign key</b>: a foreign key references a primary key in another table and is not required to be unique or non-null within its own table.</span><span class='qd'><b>Composite index</b>: a composite index spans multiple columns to speed queries but does not by definition enforce row uniqueness as the identifier.</span><span class='qd'><b>Surrogate column</b>: a surrogate column may serve as a key, but the term for the unique non-null identifier of a row is the primary key.</span>" },
{ id:"D1-008", domain:1, obj:"1.1", diff:"medium", q:"A column in the Orders table holds the CustomerID value that must already exist in the Customers table. This constraint is enforced through a:", options:["Primary key","Check constraint","Unique index","Foreign key"], answer:3, explain:"<strong>Foreign key</strong> constraints link a column to the primary key of another table and enforce that the referenced value already exists, providing referential integrity.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Primary key</b>: a primary key uniquely identifies rows within its own table and does not reference another table.</span><span class='qd'><b>Check constraint</b>: a check constraint validates a value against a rule or range, not against rows in another table.</span><span class='qd'><b>Unique index</b>: a unique index prevents duplicate values in a column but does not require the value to exist elsewhere.</span>" },
{ id:"D1-009", domain:1, obj:"1.1", diff:"easy", q:"A user receives a file with the extension .csv. What does this file format use to separate fields on each line?", options:["Commas (delimiters)","XML tags","Fixed binary blocks","SQL statements"], answer:0, explain:"A .csv file is a delimited text file that uses <strong>Commas (delimiters)</strong> to separate field values on each line, with rows separated by line breaks.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>XML tags</b>: XML tags are used in .xml files, not in comma-separated value files.</span><span class='qd'><b>Fixed binary blocks</b>: CSV is plain text, not a fixed binary block format.</span><span class='qd'><b>SQL statements</b>: a CSV stores raw values, not executable SQL statements.</span>" },
{ id:"D1-010", domain:1, obj:"1.1", diff:"easy", q:"An analyst opens a file that contains a worksheet with multiple tabs, formulas, and cell formatting. Which file extension is MOST likely?", options:[".txt",".xlsx",".json",".dat"], answer:1, explain:"<strong>.xlsx</strong> is the modern Microsoft Excel workbook format, which supports multiple worksheet tabs, formulas, and cell formatting.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>.txt</b>: a .txt file is plain text with no worksheets, formulas, or formatting.</span><span class='qd'><b>.json</b>: a .json file stores key-value structured text, not spreadsheet worksheets.</span><span class='qd'><b>.dat</b>: a .dat file is a generic data file with no defined worksheet or formula structure.</span>" },
{ id:"D1-011", domain:1, obj:"1.1", diff:"medium", q:"A web API returns the response below: {\"id\":42,\"tags\":[\"a\",\"b\"]}. Which file/data format is being used?", options:["CSV","XML","JSON","Fixed-width text"], answer:2, explain:"<strong>JSON</strong> (JavaScript Object Notation) uses curly braces for objects, square brackets for arrays, and key:value pairs, exactly as shown in the response.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>CSV</b>: CSV is a flat comma-separated grid and cannot represent nested objects or arrays like this.</span><span class='qd'><b>XML</b>: XML wraps data in angle-bracket tags, not braces and brackets.</span><span class='qd'><b>Fixed-width text</b>: fixed-width text aligns values by column position and has no braces or key names.</span>" },
{ id:"D1-012", domain:1, obj:"1.1", diff:"medium", q:"An analyst must load a legacy export where each field occupies a fixed number of character positions with no delimiter between values. This is BEST described as a:", options:["Comma-delimited file","Tab-delimited file","JSON document","Fixed-width (flat) file"], answer:3, explain:"<strong>Fixed-width (flat) file</strong> aligns each field to a set number of character positions rather than using a delimiter, so the parser reads by column position.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Comma-delimited file</b>: a comma-delimited file separates fields with commas, which the scenario explicitly lacks.</span><span class='qd'><b>Tab-delimited file</b>: a tab-delimited file uses tab characters as separators, which is still a delimiter rather than fixed positions.</span><span class='qd'><b>JSON document</b>: JSON uses named keys and braces, not fixed character columns.</span>" },
{ id:"D1-013", domain:1, obj:"1.1", diff:"easy", q:"Which of the following is an example of UNSTRUCTURED data?", options:["A scanned image of a handwritten letter","A relational table of invoices","A CSV of monthly sales","A spreadsheet of employee IDs"], answer:0, explain:"<strong>A scanned image of a handwritten letter</strong> has no predefined data model or fields, which is the defining trait of unstructured data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A relational table of invoices</b>: a relational table has rows, columns, and a schema, making it structured data.</span><span class='qd'><b>A CSV of monthly sales</b>: a CSV is organized into fixed fields and rows, so it is structured.</span><span class='qd'><b>A spreadsheet of employee IDs</b>: a spreadsheet arranges values in labeled columns, making it structured data.</span>" },
{ id:"D1-014", domain:1, obj:"1.1", diff:"medium", q:"A log entry formatted as JSON with consistent keys but no enforced relational schema is BEST classified as which type of data?", options:["Structured","Semi-structured","Unstructured","Binary-only"], answer:1, explain:"<strong>Semi-structured</strong> data has organizational markers such as JSON keys or tags but does not conform to a rigid relational schema, which fits a JSON log entry.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Structured</b>: structured data lives in a fixed relational schema of rows and columns, which JSON does not require.</span><span class='qd'><b>Unstructured</b>: unstructured data has no organizational markers at all, but JSON keys do provide structure.</span><span class='qd'><b>Binary-only</b>: the entry is human-readable text with keys, not opaque binary content.</span>" },
{ id:"D1-015", domain:1, obj:"1.1", diff:"easy", q:"Which data type is MOST appropriate for storing a value that can only be TRUE or FALSE, such as whether an account is active?", options:["String","Datetime","Boolean","Numeric"], answer:2, explain:"<strong>Boolean</strong> represents exactly two states, true or false, which is ideal for a yes/no flag like account-active status.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>String</b>: a string could hold the words but wastes space and allows invalid values beyond true/false.</span><span class='qd'><b>Datetime</b>: a datetime stores points in time, not a two-state flag.</span><span class='qd'><b>Numeric</b>: a numeric type stores numbers and does not natively constrain values to true or false.</span>" },
{ id:"D1-016", domain:1, obj:"1.1", diff:"medium", q:"An analyst needs to store monetary amounts where rounding errors are unacceptable. Which numeric data type is MOST appropriate?", options:["FLOAT","INTEGER","BOOLEAN","DECIMAL/NUMERIC"], answer:3, explain:"<strong>DECIMAL/NUMERIC</strong> stores exact fixed-point values, avoiding the binary rounding errors that can occur with currency in floating-point types.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>FLOAT</b>: a float uses binary floating point and can introduce small rounding errors that are unacceptable for money.</span><span class='qd'><b>INTEGER</b>: an integer cannot store fractional cents without scaling tricks, making it awkward for currency.</span><span class='qd'><b>BOOLEAN</b>: a boolean holds only true/false and cannot represent monetary amounts.</span>" },
{ id:"D1-017", domain:1, obj:"1.1", diff:"medium", q:"A column must store geographic point and polygon shapes for mapping store locations and delivery zones. Which data type is designed for this?", options:["Spatial","LOB","GUID","Datetime"], answer:0, explain:"<strong>Spatial</strong> data types store geometric and geographic shapes such as points and polygons, enabling location and mapping queries.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>LOB</b>: a large object type stores big binary or text blobs like images, not queryable geographic shapes.</span><span class='qd'><b>GUID</b>: a GUID is a globally unique identifier, not a geographic shape.</span><span class='qd'><b>Datetime</b>: a datetime stores time values, not spatial coordinates.</span>" },
{ id:"D1-018", domain:1, obj:"1.1", diff:"hard", q:"A distributed system must generate unique record identifiers across many servers without coordinating with a central counter. Which data type is BEST suited to act as the key?", options:["Auto-increment INTEGER","GUID/UUID","Boolean","Spatial"], answer:1, explain:"A <strong>GUID/UUID</strong> is a 128-bit value designed to be globally unique without central coordination, so independent servers can generate non-colliding keys.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Auto-increment INTEGER</b>: auto-increment relies on a single shared counter and would collide or require coordination across many servers.</span><span class='qd'><b>Boolean</b>: a boolean has only two values and cannot uniquely identify many records.</span><span class='qd'><b>Spatial</b>: a spatial type stores shapes, not unique identifiers.</span>" },
{ id:"D1-019", domain:1, obj:"1.1", diff:"medium", q:"A column intended to store full document scans and large binary photos should use which data type category?", options:["Numeric","Boolean","LOB (BLOB/CLOB)","Datetime"], answer:2, explain:"<strong>LOB (BLOB/CLOB)</strong> large object types are built to store very large binary or character data such as document scans and photos.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Boolean</b>: a boolean stores only true/false and cannot hold a binary file.</span><span class='qd'><b>Numeric</b>: a numeric type stores numbers, not binary file content.</span><span class='qd'><b>Datetime</b>: a datetime stores timestamps, not large binary objects.</span>" },
{ id:"D1-020", domain:1, obj:"1.1", diff:"easy", q:"In a database, a field that has no value at all (not zero, not an empty string) is represented by:", options:["A Boolean false","A zero","A space character","A NULL"], answer:3, explain:"<strong>A NULL</strong> represents the absence of any value, which is distinct from zero, an empty string, or false.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A zero</b>: zero is a defined numeric value, not the absence of a value.</span><span class='qd'><b>A space character</b>: a space is a real character stored in the field, not a missing value.</span><span class='qd'><b>A Boolean false</b>: false is a defined boolean value, which is different from having no value.</span>" },
{ id:"D1-021", domain:1, obj:"1.1", diff:"medium", q:"In a star-schema data warehouse, the central table that stores measurable business events such as sales amounts is called the:", options:["Fact table","Dimension table","Bridge table","Lookup table"], answer:0, explain:"The <strong>Fact table</strong> sits at the center of a star schema and stores quantitative measures (facts) such as sales amounts along with foreign keys to dimensions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Dimension table</b>: a dimension table stores descriptive attributes like product or date, not the measurable events.</span><span class='qd'><b>Bridge table</b>: a bridge table resolves many-to-many relationships between facts and dimensions, not the central measures.</span><span class='qd'><b>Lookup table</b>: a lookup table maps codes to descriptions and is a supporting reference, not the fact store.</span>" },
{ id:"D1-022", domain:1, obj:"1.1", diff:"medium", q:"A dimensional model needs a table that holds descriptive attributes such as product name, category, and color to give context to sales facts. This table is a:", options:["Fact table","Dimension table","Junction table","Staging table"], answer:1, explain:"A <strong>Dimension table</strong> stores descriptive, contextual attributes such as product name, category, and color that analysts use to slice and filter the facts.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Fact table</b>: a fact table holds numeric measures and keys, not descriptive attributes.</span><span class='qd'><b>Junction table</b>: a junction table resolves many-to-many relationships and does not store descriptive context.</span><span class='qd'><b>Staging table</b>: a staging table temporarily holds raw data during loading, not the modeled descriptive attributes.</span>" },
{ id:"D1-023", domain:1, obj:"1.1", diff:"hard", q:"A retailer must keep full history of a customer's address changes so old sales still map to the address used at the time. Which dimensional modeling technique handles this?", options:["A bridge table","A fact-less fact table","A Slowly Changing Dimension (Type 2)","A surrogate-only key"], answer:2, explain:"A <strong>Slowly Changing Dimension (Type 2)</strong> adds a new dimension row each time an attribute changes, preserving full history so past facts link to the value that was current then.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A bridge table</b>: a bridge table resolves many-to-many relationships and does not track historical attribute changes.</span><span class='qd'><b>A fact-less fact table</b>: a fact-less fact table records events without measures and does not preserve dimension history.</span><span class='qd'><b>A surrogate-only key</b>: a surrogate key alone provides a unique identifier but does not by itself capture change history.</span>" },
{ id:"D1-024", domain:1, obj:"1.1", diff:"medium", q:"A many-to-many relationship exists between students and the courses they enroll in. Which structure resolves this in a relational design?", options:["A single wide table with repeating course columns","A spatial index","A view over both tables","A bridge/junction table linking the two keys"], answer:3, explain:"<strong>A bridge/junction table linking the two keys</strong> stores each student-course pair as a row, cleanly resolving a many-to-many relationship.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A single wide table with repeating course columns</b>: repeating columns violates normalization and cannot handle an unlimited number of courses.</span><span class='qd'><b>A view over both tables</b>: a view only presents existing data and cannot by itself model the many-to-many link.</span><span class='qd'><b>A spatial index</b>: a spatial index accelerates geographic queries and is unrelated to resolving relationships.</span>" },
{ id:"D1-025", domain:1, obj:"1.1", diff:"medium", q:"A query that filters customers by last name runs slowly on a large table. Which database object would MOST improve lookup speed on that column?", options:["An index","A foreign key","A trigger","A view"], answer:0, explain:"<strong>An index</strong> creates a sorted structure on a column so the database can locate matching rows without scanning the entire table, improving lookup speed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A foreign key</b>: a foreign key enforces referential integrity and does not by itself speed up filtering.</span><span class='qd'><b>A trigger</b>: a trigger runs code on data changes and does not accelerate read queries.</span><span class='qd'><b>A view</b>: a view is a saved query and does not inherently speed up the underlying lookup.</span>" },
{ id:"D1-026", domain:1, obj:"1.1", diff:"easy", q:"Which type of database is specifically optimized for storing and traversing relationships between entities, such as social-network connections?", options:["Relational database","Graph database","Columnar database","Flat file"], answer:1, explain:"A <strong>Graph database</strong> stores entities as nodes and relationships as edges, making it efficient to traverse connections like friend-of-a-friend links.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Relational database</b>: a relational database can model relationships but becomes slow for deep multi-hop traversals compared to a graph engine.</span><span class='qd'><b>Columnar database</b>: a columnar database is optimized for analytical aggregation over columns, not relationship traversal.</span><span class='qd'><b>Flat file</b>: a flat file has no relationship traversal capability at all.</span>" },
{ id:"D1-027", domain:1, obj:"1.1", diff:"medium", q:"An analyst must store rapidly changing session data accessed only by a unique session ID with sub-millisecond reads. Which non-relational store fits BEST?", options:["Relational database","Graph database","Key-value store","Columnar warehouse"], answer:2, explain:"A <strong>Key-value store</strong> retrieves a value directly by its key with very low latency, which is ideal for session lookups by session ID.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Graph database</b>: a graph database is built for relationship traversal, not simple key lookups.</span><span class='qd'><b>Relational database</b>: a relational database adds schema and join overhead that is unnecessary for a single-key lookup.</span><span class='qd'><b>Columnar warehouse</b>: a columnar warehouse is tuned for large analytical scans, not single-record session reads.</span>" },
{ id:"D1-028", domain:1, obj:"1.1", diff:"medium", q:"Which statement BEST distinguishes a relational database from most non-relational (NoSQL) databases?", options:["Relational databases never use keys","Relational databases cannot store text","NoSQL databases always guarantee ACID across clusters","Relational databases enforce a predefined schema while many NoSQL stores are schema-flexible"], answer:3, explain:"The key distinction is that <strong>Relational databases enforce a predefined schema while many NoSQL stores are schema-flexible</strong>, allowing NoSQL records to vary in structure.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Relational databases never use keys</b>: relational databases rely heavily on primary and foreign keys, so this is false.</span><span class='qd'><b>NoSQL databases always guarantee ACID across clusters</b>: many NoSQL systems favor availability and eventual consistency rather than strict cluster-wide ACID.</span><span class='qd'><b>Relational databases cannot store text</b>: relational databases store text in string and character types, so this is false.</span>" },
{ id:"D1-029", domain:1, obj:"1.1", diff:"easy", q:"A schema in a relational database BEST refers to:", options:["The logical structure defining tables, columns, and relationships","A single row of data","A backup of the database","An encryption key"], answer:0, explain:"A schema is <strong>The logical structure defining tables, columns, and relationships</strong>, serving as the blueprint for how data is organized.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A single row of data</b>: a row is one record, not the overall structure.</span><span class='qd'><b>A backup of the database</b>: a backup is a copy for recovery, not the structural definition.</span><span class='qd'><b>An encryption key</b>: an encryption key protects data and is unrelated to the structural blueprint.</span>" },
{ id:"D1-030", domain:1, obj:"1.1", diff:"medium", q:"A datetime column stores both a date and a time but the team needs to compare events across global offices in different time zones reliably. Which approach is BEST?", options:["Store local time only with no zone","Store timestamps in UTC and convert for display","Store the date as a string","Store only the time portion"], answer:1, explain:"Storing <strong>Store timestamps in UTC and convert for display</strong> gives a single unambiguous reference point so events from different offices can be compared accurately.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Store local time only with no zone</b>: local-only times are ambiguous and cannot be compared reliably across zones.</span><span class='qd'><b>Store the date as a string</b>: a string loses datetime arithmetic and validation, making comparison error-prone.</span><span class='qd'><b>Store only the time portion</b>: dropping the date makes it impossible to order events across days.</span>" },
{ id:"D1-031", domain:1, obj:"1.1", diff:"easy", q:"Which file type is a plain-text file with no formatting, commonly used for simple notes or raw output?", options:[".xlsx",".json",".txt",".jpg"], answer:2, explain:"<strong>.txt</strong> is a plain-text file with no formatting, ideal for simple notes or raw program output.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>.xlsx</b>: .xlsx is a formatted spreadsheet workbook, not plain text.</span><span class='qd'><b>.json</b>: .json is structured text with keys and braces rather than free-form plain text.</span><span class='qd'><b>.jpg</b>: .jpg is a compressed image format, not text.</span>" },
{ id:"D1-032", domain:1, obj:"1.1", diff:"easy", q:"An analyst receives product photos to attach to records. The files end in .jpg. This format is an example of:", options:["A structured data file","A SQL script","A delimited text file","An image (binary) file"], answer:3, explain:"<strong>An image (binary) file</strong> describes a .jpg, which is compressed binary picture data rather than readable text or tabular records.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A structured data file</b>: a .jpg holds pixel data, not rows and columns, so it is unstructured binary content.</span><span class='qd'><b>A delimited text file</b>: a delimited text file separates values with characters like commas, which an image does not.</span><span class='qd'><b>A SQL script</b>: a SQL script contains executable statements, not image data.</span>" },
{ id:"D1-033", domain:1, obj:"1.1", diff:"hard", q:"An analyst must choose a column type for U.S. ZIP codes that include a leading zero, such as 02134. Which choice avoids losing the leading zero?", options:["String/VARCHAR","INTEGER","FLOAT","BOOLEAN"], answer:0, explain:"<strong>String/VARCHAR</strong> preserves leading zeros because it stores the characters exactly, whereas numeric types drop the leading zero.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>INTEGER</b>: an integer would interpret 02134 as 2134 and strip the leading zero.</span><span class='qd'><b>FLOAT</b>: a float treats the value as a number and also loses the leading zero, plus risks rounding.</span><span class='qd'><b>BOOLEAN</b>: a boolean holds only true/false and cannot store a ZIP code at all.</span>" },
{ id:"D1-034", domain:1, obj:"1.1", diff:"medium", q:"A table design uses a meaningless auto-generated key (such as an identity column) instead of a real-world attribute as the primary key. This is called a:", options:["Natural key","Surrogate key","Foreign key","Candidate key"], answer:1, explain:"A <strong>Surrogate key</strong> is a system-generated, meaningless identifier used as the primary key, insulating the design from changes in real-world attributes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Natural key</b>: a natural key uses a real-world attribute such as an email, which is the opposite of a generated key.</span><span class='qd'><b>Foreign key</b>: a foreign key references another table's key and is not the generated primary identifier.</span><span class='qd'><b>Candidate key</b>: a candidate key is any column that could serve as a primary key, not specifically a generated one.</span>" },
{ id:"D1-035", domain:1, obj:"1.1", diff:"medium", q:"An analyst examines a dataset of free-form customer review paragraphs with no consistent fields. This data is BEST described as:", options:["Structured","Semi-structured","Unstructured","Relational"], answer:2, explain:"<strong>Unstructured</strong> data lacks a predefined model or consistent fields, which describes free-form review paragraphs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Structured</b>: structured data has a fixed schema of rows and columns, which free text lacks.</span><span class='qd'><b>Semi-structured</b>: semi-structured data has organizational markers like tags or keys, which raw paragraphs do not have.</span><span class='qd'><b>Relational</b>: relational data is stored in keyed tables, not as loose text paragraphs.</span>" },
{ id:"D1-036", domain:1, obj:"1.1", diff:"hard", q:"A data engineer must store deeply nested configuration data with arrays and objects in a single document while keeping it human-readable. Which format is the BEST fit?", options:["CSV","Fixed-width text","BLOB","JSON"], answer:3, explain:"<strong>JSON</strong> natively represents nested objects and arrays in a human-readable text format, making it ideal for hierarchical configuration data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>CSV</b>: CSV is a flat grid and cannot represent nesting or arrays cleanly.</span><span class='qd'><b>Fixed-width text</b>: fixed-width text is flat and positional, with no support for nested structures.</span><span class='qd'><b>BLOB</b>: a BLOB stores opaque binary and is not human-readable structured text.</span>" },
{ id:"D1-037", domain:1, obj:"1.1", diff:"medium", q:"Which ACID property prevents two simultaneous transactions from seeing each other's uncommitted intermediate changes?", options:["Isolation","Consistency","Atomicity","Durability"], answer:0, explain:"<strong>Isolation</strong> ensures concurrent transactions do not see each other's uncommitted changes, so each behaves as if it ran alone.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Atomicity</b>: atomicity makes a single transaction all-or-nothing but does not govern interaction between concurrent transactions.</span><span class='qd'><b>Consistency</b>: consistency keeps data valid against constraints, not the visibility of in-progress changes.</span><span class='qd'><b>Durability</b>: durability ensures committed changes persist after a crash, unrelated to concurrent visibility.</span>" },
{ id:"D1-038", domain:1, obj:"1.1", diff:"easy", q:"Which data type is the BEST choice for storing a person's full name?", options:["Numeric","String (VARCHAR)","Boolean","Spatial"], answer:1, explain:"<strong>String (VARCHAR)</strong> stores variable-length character text, which is appropriate for names of differing lengths.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Numeric</b>: a numeric type stores numbers and cannot hold alphabetic text.</span><span class='qd'><b>Boolean</b>: a boolean holds only true/false, which cannot represent a name.</span><span class='qd'><b>Spatial</b>: a spatial type stores geographic shapes, not names.</span>" },
{ id:"D1-039", domain:1, obj:"1.1", diff:"hard", q:"A snowflake schema differs from a star schema primarily because it:", options:["Removes all fact tables","Stores only unstructured data","Normalizes dimension tables into multiple related sub-tables","Eliminates the need for keys"], answer:2, explain:"A snowflake schema <strong>Normalizes dimension tables into multiple related sub-tables</strong>, branching dimensions out to reduce redundancy compared to the flatter star schema.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Removes all fact tables</b>: a snowflake schema still has a central fact table; only the dimensions are normalized.</span><span class='qd'><b>Stores only unstructured data</b>: both star and snowflake schemas model structured data.</span><span class='qd'><b>Eliminates the need for keys</b>: keys are still required to relate facts and dimensions.</span>" },
{ id:"D1-040", domain:1, obj:"1.1", diff:"medium", q:"An analyst needs to store a column of timestamps capturing the exact moment each order was placed. Which data type is MOST appropriate?", options:["String","Integer","Boolean","Datetime/Timestamp"], answer:3, explain:"<strong>Datetime/Timestamp</strong> stores a precise point in time and supports date arithmetic, sorting, and validation for order events.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>String</b>: a string loses date arithmetic and allows invalid formats.</span><span class='qd'><b>Boolean</b>: a boolean stores only true/false and cannot represent a time.</span><span class='qd'><b>Integer</b>: an integer alone is not a recognizable timestamp and complicates date operations.</span>" },
{ id:"D1-041", domain:1, obj:"1.2", diff:"easy", q:"An analyst needs to pull live currency exchange rates from a third-party provider into a dashboard. Which data source type is MOST appropriate?", options:["A REST API/web service","A flat CSV export","A scanned PDF","A local text file"], answer:0, explain:"<strong>A REST API/web service</strong> provides programmatic, real-time access to a provider's data such as exchange rates, returning results on request.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A flat CSV export</b>: a static CSV is a point-in-time snapshot and would not reflect live rates.</span><span class='qd'><b>A scanned PDF</b>: a scanned PDF is unstructured and cannot deliver live programmatic data.</span><span class='qd'><b>A local text file</b>: a local file is static and would require manual updates to stay current.</span>" },
{ id:"D1-042", domain:1, obj:"1.2", diff:"medium", q:"A web service returns data only after the caller supplies a token in the request header. This token is MOST likely used for:", options:["Compressing the response","Authenticating and authorizing the API request","Encrypting the database at rest","Formatting the JSON output"], answer:1, explain:"An API token in the request header is used for <strong>Authenticating and authorizing the API request</strong>, proving the caller is permitted to access the service.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Compressing the response</b>: compression is negotiated separately, not via an authorization token.</span><span class='qd'><b>Encrypting the database at rest</b>: at-rest encryption is a server-side storage concern unrelated to a request token.</span><span class='qd'><b>Formatting the JSON output</b>: output format is controlled by content-type headers or parameters, not the auth token.</span>" },
{ id:"D1-043", domain:1, obj:"1.2", diff:"medium", q:"An organization wants to extract data from an internal sales system by querying its database directly through a connection string. This is an example of using which data source?", options:["A public API","Web scraping","A direct database connection","A flat file import"], answer:2, explain:"<strong>A direct database connection</strong> uses a connection string and driver to query the source database tables directly, a common internal data source method.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A public API</b>: a public API exposes data through web endpoints, not a direct database connection string.</span><span class='qd'><b>Web scraping</b>: web scraping extracts data from rendered web pages, not from a database connection.</span><span class='qd'><b>A flat file import</b>: a flat file import loads exported files, not a live database query.</span>" },
{ id:"D1-044", domain:1, obj:"1.2", diff:"hard", q:"A retailer wants competitor prices that are only published on public product web pages with no API available. Which acquisition method is MOST appropriate, assuming it is permitted?", options:["Direct database connection","Querying a data warehouse","Reading the retailer's own logs","Web scraping"], answer:3, explain:"<strong>Web scraping</strong> programmatically extracts data from rendered web pages, which is the appropriate method when only a public webpage is available and no API exists.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Direct database connection</b>: the analyst has no access to a competitor's database, so a connection is impossible.</span><span class='qd'><b>Reading the retailer's own logs</b>: internal logs contain the retailer's own activity, not competitor prices.</span><span class='qd'><b>Querying a data warehouse</b>: a warehouse holds already-collected internal data, not live competitor web prices.</span>" },
{ id:"D1-045", domain:1, obj:"1.2", diff:"easy", q:"Server log files that automatically record events such as user logins and errors are an example of:", options:["Machine-generated data","Survey data","Manually entered data","Imputed data"], answer:0, explain:"<strong>Machine-generated data</strong> is produced automatically by systems and devices, which includes server logs of logins and errors.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Survey data</b>: survey data is collected from people answering questions, not produced automatically by a server.</span><span class='qd'><b>Manually entered data</b>: manual data is typed in by humans, whereas logs are generated by the system.</span><span class='qd'><b>Imputed data</b>: imputed data is estimated to fill gaps, not directly recorded by a machine.</span>" },
{ id:"D1-046", domain:1, obj:"1.2", diff:"medium", q:"An analyst studies clickstream data showing the sequence of pages each visitor viewed on a website. This is BEST categorized as:", options:["Survey data","Website/behavioral data","Financial ledger data","Sensor telemetry data"], answer:1, explain:"<strong>Website/behavioral data</strong> captures user interactions such as page views and click sequences, which is exactly what clickstream data records.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Survey data</b>: survey data comes from questionnaires, not automatic page-view tracking.</span><span class='qd'><b>Financial ledger data</b>: ledger data records monetary transactions, not browsing behavior.</span><span class='qd'><b>Sensor telemetry data</b>: telemetry comes from physical devices, whereas clickstream comes from web interactions.</span>" },
{ id:"D1-047", domain:1, obj:"1.2", diff:"medium", q:"An API endpoint returns 1,000 records per call and provides a 'next page' token to retrieve more. This mechanism is known as:", options:["Throttling","Caching","Pagination","Authentication"], answer:2, explain:"<strong>Pagination</strong> splits a large result set into pages, using a token or offset so the caller can retrieve subsequent batches.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Throttling</b>: throttling limits how often requests are allowed, not how results are split into pages.</span><span class='qd'><b>Caching</b>: caching stores responses to speed repeat requests, not the page-by-page retrieval mechanism.</span><span class='qd'><b>Authentication</b>: authentication verifies the caller and is unrelated to splitting results.</span>" },
{ id:"D1-048", domain:1, obj:"1.2", diff:"hard", q:"An analyst's script begins receiving HTTP 429 'Too Many Requests' responses from an API. What is the MOST likely cause?", options:["The API requires a different file format","The data is unstructured","The database is denormalized","Rate limiting/throttling has been exceeded"], answer:3, explain:"An HTTP 429 response indicates <strong>Rate limiting/throttling has been exceeded</strong>, meaning the script sent more requests than the API permits in the time window.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The API requires a different file format</b>: a format mismatch would typically return a 4xx like 415, not specifically 429.</span><span class='qd'><b>The database is denormalized</b>: schema design on the back end does not produce a 429 response.</span><span class='qd'><b>The data is unstructured</b>: data structure does not cause a too-many-requests error.</span>" },
{ id:"D1-049", domain:1, obj:"1.2", diff:"easy", q:"Which of the following is the BEST example of a primary, first-party data source for a company?", options:["The company's own CRM transaction records","A purchased industry report","A competitor's website","A public government dataset"], answer:0, explain:"<strong>The company's own CRM transaction records</strong> are first-party data the company collects directly from its customers, the most controlled and reliable source.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A purchased industry report</b>: a purchased report is third-party data aggregated by an outside provider.</span><span class='qd'><b>A competitor's website</b>: a competitor's site is external, not the company's own collected data.</span><span class='qd'><b>A public government dataset</b>: a public dataset is third-party data, not first-party records.</span>" },
{ id:"D1-050", domain:1, obj:"1.2", diff:"medium", q:"A team subscribes to a feed of demographic data compiled and sold by an outside vendor. This is BEST described as:", options:["First-party data","Third-party data","Second-party data","Machine data"], answer:1, explain:"<strong>Third-party data</strong> is collected and sold by an external organization that has no direct relationship with the data subjects, such as a demographic data vendor.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>First-party data</b>: first-party data is collected by the company itself directly from its own customers.</span><span class='qd'><b>Second-party data</b>: second-party data is another organization's first-party data shared directly with a partner, not bought from a broad vendor.</span><span class='qd'><b>Machine data</b>: machine data is generated by devices and systems, not purchased demographic feeds.</span>" },
{ id:"D1-051", domain:1, obj:"1.2", diff:"medium", q:"An analyst integrates Internet of Things (IoT) temperature readings streamed from factory sensors. This source is BEST classified as:", options:["Survey data","Web scraping output","Sensor/telemetry (machine) data","Manually keyed data"], answer:2, explain:"<strong>Sensor/telemetry (machine) data</strong> is automatically emitted by physical devices such as IoT temperature sensors, often as continuous streams.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Survey data</b>: survey data is gathered from people answering questions, not from device readings.</span><span class='qd'><b>Web scraping output</b>: web scraping pulls data from web pages, not from physical sensors.</span><span class='qd'><b>Manually keyed data</b>: manually keyed data is typed by humans, whereas sensor data is automatic.</span>" },
{ id:"D1-052", domain:1, obj:"1.2", diff:"hard", q:"A REST API documentation states it returns data in JSON and supports filtering via query parameters. The BEST reason to use query parameters rather than downloading everything is to:", options:["Encrypt the response","Guarantee ACID compliance","Change the database schema","Retrieve only the needed subset, reducing payload and load time"], answer:3, explain:"Using query parameters lets the caller <strong>Retrieve only the needed subset, reducing payload and load time</strong> by filtering server-side instead of transferring all records.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Encrypt the response</b>: encryption is handled by transport security like TLS, not by query parameters.</span><span class='qd'><b>Change the database schema</b>: query parameters filter results and never alter the underlying schema.</span><span class='qd'><b>Guarantee ACID compliance</b>: ACID is a transaction property of the database, not a function of API filtering.</span>" },
{ id:"D1-053", domain:1, obj:"1.2", diff:"easy", q:"Which data source provides a static, point-in-time export rather than continuously updated data?", options:["A downloaded CSV file","A streaming API","A live database connection","A real-time message queue"], answer:0, explain:"<strong>A downloaded CSV file</strong> is a static snapshot captured at the moment of export and does not update on its own.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A streaming API</b>: a streaming API delivers continuous, real-time data rather than a static snapshot.</span><span class='qd'><b>A live database connection</b>: a live connection reflects current data each time it is queried.</span><span class='qd'><b>A real-time message queue</b>: a message queue delivers events as they occur, not a fixed snapshot.</span>" },
{ id:"D1-054", domain:1, obj:"1.2", diff:"medium", q:"An analyst must combine the company's own purchase history with a partner airline's loyalty data shared directly under an agreement. The partner's data is an example of:", options:["First-party data","Second-party data","Third-party data","Synthetic data"], answer:1, explain:"<strong>Second-party data</strong> is another organization's first-party data shared directly with a trusted partner, which describes the airline's loyalty data shared under agreement.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>First-party data</b>: first-party data is data the company collected itself, not received from a partner.</span><span class='qd'><b>Third-party data</b>: third-party data is bought from a broker with no direct relationship, unlike a direct partner share.</span><span class='qd'><b>Synthetic data</b>: synthetic data is artificially generated, not real partner loyalty records.</span>" },
{ id:"D1-055", domain:1, obj:"1.2", diff:"medium", q:"Application logs, system event logs, and network device logs are MOST commonly used by analysts to:", options:["Store customer billing addresses","Replace the production database","Investigate behavior, performance, and security events","Encrypt data in transit"], answer:2, explain:"Logs are most commonly used to <strong>Investigate behavior, performance, and security events</strong> because they record what systems and users did over time.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Store customer billing addresses</b>: billing addresses belong in a customer database, not in event logs.</span><span class='qd'><b>Replace the production database</b>: logs supplement a system but do not serve as its transactional database.</span><span class='qd'><b>Encrypt data in transit</b>: encryption is a network control, not a function of log files.</span>" },
{ id:"D1-056", domain:1, obj:"1.2", diff:"hard", q:"A company's mobile app sends usage events to a server that buffers them for later batch processing. The component that temporarily holds these incoming events in order is BEST described as a:", options:["Data dictionary","Pivot table","Foreign key","Message queue"], answer:3, explain:"A <strong>Message queue</strong> buffers incoming events in order so producers and consumers can operate at different rates, supporting later batch processing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data dictionary</b>: a data dictionary documents field definitions and does not buffer events.</span><span class='qd'><b>Foreign key</b>: a foreign key enforces relationships in a table and has nothing to do with event buffering.</span><span class='qd'><b>Pivot table</b>: a pivot table summarizes data for analysis, not a transport buffer.</span>" },
{ id:"D1-057", domain:1, obj:"1.2", diff:"easy", q:"Which of the following is the BEST example of structured data coming directly from a transactional source?", options:["Rows from a point-of-sale (POS) database","A folder of audio recordings","A set of social media images","Free-form email bodies"], answer:0, explain:"<strong>Rows from a point-of-sale (POS) database</strong> are structured, schema-defined transactional records, the classic structured data source.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A folder of audio recordings</b>: audio files are unstructured binary data.</span><span class='qd'><b>A set of social media images</b>: images are unstructured binary content with no schema.</span><span class='qd'><b>Free-form email bodies</b>: free-form text lacks a fixed schema and is unstructured.</span>" },
{ id:"D1-058", domain:1, obj:"1.2", diff:"medium", q:"An analyst is told to consume data from an endpoint at https://api.vendor.com/v2/sales. The 'v2' in the path MOST likely indicates:", options:["The number of records returned","The API version","The encryption strength","The database table name"], answer:1, explain:"The 'v2' segment indicates <strong>The API version</strong>, letting providers evolve their interface while supporting older clients on earlier versions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The number of records returned</b>: record counts are controlled by parameters or pagination, not the version path.</span><span class='qd'><b>The encryption strength</b>: encryption is handled by HTTPS/TLS, not a version label.</span><span class='qd'><b>The database table name</b>: the path segment names the API resource and version, not an internal table.</span>" },
{ id:"D1-059", domain:1, obj:"1.2", diff:"medium", q:"When acquiring data by web scraping, which factor MUST an analyst evaluate first to avoid legal and ethical problems?", options:["The font used on the page","The color scheme of the website","The site's terms of service and robots.txt","The number of images on the page"], answer:2, explain:"Before scraping, the analyst must check <strong>The site's terms of service and robots.txt</strong> to confirm that automated collection is permitted and avoid legal or ethical violations.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The font used on the page</b>: fonts are presentation details irrelevant to whether scraping is allowed.</span><span class='qd'><b>The color scheme of the website</b>: styling has no bearing on permission to collect data.</span><span class='qd'><b>The number of images on the page</b>: image count does not determine the legality of scraping.</span>" },
{ id:"D1-060", domain:1, obj:"1.2", diff:"hard", q:"An analyst must choose between an API that pushes events in real time and a nightly file export. For a dashboard that must reflect inventory within seconds, which source is appropriate and why?", options:["The nightly file, because it is simpler","Either, since latency does not matter","The nightly file, because it guarantees accuracy","The real-time API, because it delivers low-latency current data"], answer:3, explain:"<strong>The real-time API, because it delivers low-latency current data</strong> is correct, since a within-seconds dashboard needs continuously updated values that a nightly batch cannot provide.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The nightly file, because it is simpler</b>: simplicity does not meet the within-seconds freshness requirement.</span><span class='qd'><b>The nightly file, because it guarantees accuracy</b>: a nightly file is up to a day stale, so it cannot reflect current inventory.</span><span class='qd'><b>Either, since latency does not matter</b>: the scenario explicitly requires seconds-level latency, so latency clearly matters.</span>" },
{ id:"D1-061", domain:1, obj:"1.3", diff:"easy", q:"A company runs all its servers in its own building, managing the hardware, cooling, and physical security itself. This deployment model is:", options:["On-premise","Public cloud","Software as a Service","Serverless"], answer:0, explain:"<strong>On-premise</strong> means the organization hosts and manages its own hardware and facilities, including cooling and physical security, in its own location.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Public cloud</b>: public cloud runs on a provider's shared infrastructure, not the company's own building.</span><span class='qd'><b>Software as a Service</b>: SaaS delivers applications over the internet, not self-hosted hardware.</span><span class='qd'><b>Serverless</b>: serverless abstracts servers away on a cloud platform, the opposite of managing your own hardware.</span>" },
{ id:"D1-062", domain:1, obj:"1.3", diff:"medium", q:"A team rents virtual machines, storage, and networking from a cloud provider and installs its own operating systems and software on them. Which service model is this?", options:["PaaS","IaaS","SaaS","FaaS"], answer:1, explain:"<strong>IaaS</strong> (Infrastructure as a Service) provides raw compute, storage, and networking while the customer manages the operating system and applications.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>PaaS</b>: PaaS supplies a managed runtime and platform, removing OS management, which contradicts installing your own OS.</span><span class='qd'><b>SaaS</b>: SaaS delivers finished applications, not raw VMs to configure.</span><span class='qd'><b>FaaS</b>: FaaS runs individual functions without managing servers or operating systems.</span>" },
{ id:"D1-063", domain:1, obj:"1.3", diff:"medium", q:"An analyst uses a fully managed cloud database where the provider handles patching, backups, and the underlying OS, and the analyst only manages the data and schema. Which service model is this?", options:["IaaS","SaaS","PaaS","On-premise"], answer:2, explain:"<strong>PaaS</strong> (Platform as a Service) provides a managed platform such as a database service where the provider handles the OS, patching, and backups while the customer manages data and schema.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>IaaS</b>: IaaS would require the customer to manage the OS and database software themselves.</span><span class='qd'><b>SaaS</b>: SaaS delivers a complete end-user application, not a managed platform for building on.</span><span class='qd'><b>On-premise</b>: on-premise means the company manages everything itself, contrary to provider-managed patching.</span>" },
{ id:"D1-064", domain:1, obj:"1.3", diff:"easy", q:"Using a web-based spreadsheet or BI tool entirely through a browser, with no installation and the vendor managing everything, is an example of which service model?", options:["IaaS","PaaS","Bare metal","SaaS"], answer:3, explain:"<strong>SaaS</strong> (Software as a Service) delivers a complete application over the internet where the vendor manages all underlying layers and the user just consumes it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>IaaS</b>: IaaS provides raw infrastructure, not a ready-to-use browser application.</span><span class='qd'><b>PaaS</b>: PaaS provides a development/runtime platform, not a finished end-user app.</span><span class='qd'><b>Bare metal</b>: bare metal is dedicated physical hardware, the opposite of a managed browser app.</span>" },
{ id:"D1-065", domain:1, obj:"1.3", diff:"hard", q:"An organization wants to keep sensitive workloads on its own private infrastructure while bursting less-sensitive analytics to a public cloud during peak demand. This combined approach is called a:", options:["Hybrid cloud","Community cloud","Pure public cloud","Pure on-premise"], answer:0, explain:"A <strong>Hybrid cloud</strong> blends private/on-premise infrastructure with public cloud, letting an organization keep sensitive workloads private while bursting others to the public cloud.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Community cloud</b>: a community cloud is shared among organizations with common requirements, not a mix of private and public for one org.</span><span class='qd'><b>Pure public cloud</b>: a pure public cloud keeps nothing on private infrastructure, contradicting the sensitive-workload requirement.</span><span class='qd'><b>Pure on-premise</b>: a pure on-premise model uses no public cloud, so it cannot burst to one.</span>" },
{ id:"D1-066", domain:1, obj:"1.3", diff:"medium", q:"Which storage type presents raw, unformatted volumes that an operating system formats and uses like a local disk, ideal for databases needing low latency?", options:["Object storage","Block storage","File storage","Cold archive storage"], answer:1, explain:"<strong>Block storage</strong> presents raw volumes that the OS formats and treats like a directly attached disk, offering the low latency databases require.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Object storage</b>: object storage accesses data as objects via an API and is not mounted as a raw disk for a database.</span><span class='qd'><b>File storage</b>: file storage provides a shared file system over a network protocol, with more overhead than raw block access.</span><span class='qd'><b>Cold archive storage</b>: cold archive is for infrequently accessed data with high retrieval latency, the opposite of low-latency needs.</span>" },
{ id:"D1-067", domain:1, obj:"1.3", diff:"medium", q:"A team stores millions of images and backups as objects accessed by unique keys over HTTP, with virtually unlimited scalability. This is which storage type?", options:["Block storage","Local SSD","Object storage","RAID array"], answer:2, explain:"<strong>Object storage</strong> stores data as objects addressed by unique keys over HTTP and scales massively, making it ideal for images and backups.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Block storage</b>: block storage is mounted as raw volumes and does not use HTTP key-based object access.</span><span class='qd'><b>Local SSD</b>: a local SSD is directly attached, limited in capacity, and not accessed as web objects.</span><span class='qd'><b>RAID array</b>: a RAID array is a disk redundancy technique, not an object-over-HTTP service.</span>" },
{ id:"D1-068", domain:1, obj:"1.3", diff:"medium", q:"Several users need to access the same documents through a shared network drive using a protocol like SMB or NFS. Which storage type fits this need?", options:["Object storage","Block storage","Tape backup","File (shared) storage"], answer:3, explain:"<strong>File (shared) storage</strong> presents a hierarchical file system accessed over protocols like SMB or NFS, enabling multiple users to share the same files.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Object storage</b>: object storage uses key-based API access, not a mounted shared file system.</span><span class='qd'><b>Block storage</b>: block storage attaches a raw volume to one host, not a shared file share for many users.</span><span class='qd'><b>Tape backup</b>: tape is offline sequential media for archival, not live shared access.</span>" },
{ id:"D1-069", domain:1, obj:"1.3", diff:"hard", q:"A developer packages an analytics application with its libraries and dependencies into a single lightweight, portable unit that runs the same on any host. This unit is a:", options:["Container","Virtual machine","Bare-metal server","Data lake"], answer:0, explain:"A <strong>Container</strong> bundles an application with its dependencies into a lightweight, portable unit that shares the host OS kernel and runs consistently across environments.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Virtual machine</b>: a VM includes a full guest operating system, making it heavier and slower to start than a container.</span><span class='qd'><b>Bare-metal server</b>: bare metal is physical hardware, not a packaged portable application unit.</span><span class='qd'><b>Data lake</b>: a data lake is a storage repository for raw data, not an application package.</span>" },
{ id:"D1-070", domain:1, obj:"1.3", diff:"medium", q:"Which technology is commonly used to orchestrate, scale, and manage large numbers of containers across a cluster?", options:["Tableau","Kubernetes","Pandas","SSMS"], answer:1, explain:"<strong>Kubernetes</strong> is a container orchestration platform that automates deploying, scaling, and managing containers across a cluster of hosts.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Tableau</b>: Tableau is a business intelligence visualization tool, not a container orchestrator.</span><span class='qd'><b>Pandas</b>: pandas is a Python data-analysis library, unrelated to managing containers.</span><span class='qd'><b>SSMS</b>: SQL Server Management Studio administers SQL Server databases, not container clusters.</span>" },
{ id:"D1-071", domain:1, obj:"1.3", diff:"easy", q:"Which is a key advantage of cloud computing over a fully on-premise deployment for a growing analytics workload?", options:["Guaranteed zero cost","No need for any security controls","Elastic scalability to add resources on demand","Elimination of the internet"], answer:2, explain:"<strong>Elastic scalability to add resources on demand</strong> lets a growing workload scale up or down quickly without buying physical hardware, a core cloud advantage.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Guaranteed zero cost</b>: cloud usage incurs costs and can become expensive at scale, so it is never free.</span><span class='qd'><b>No need for any security controls</b>: the cloud uses a shared responsibility model and still requires security controls.</span><span class='qd'><b>Elimination of the internet</b>: cloud services typically depend on internet connectivity rather than eliminating it.</span>" },
{ id:"D1-072", domain:1, obj:"1.3", diff:"hard", q:"In the cloud shared responsibility model under IaaS, which task is the CUSTOMER typically responsible for?", options:["Maintaining the physical data center","Powering the server racks","Securing the hypervisor hardware","Patching the guest operating system and applications"], answer:3, explain:"Under IaaS, the customer is responsible for <strong>Patching the guest operating system and applications</strong>, while the provider secures the underlying physical and virtualization infrastructure.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Maintaining the physical data center</b>: the provider owns and maintains the physical facility, not the customer.</span><span class='qd'><b>Securing the hypervisor hardware</b>: the hypervisor and host hardware are the provider's responsibility in IaaS.</span><span class='qd'><b>Powering the server racks</b>: physical power and racks are managed by the cloud provider.</span>" },
{ id:"D1-073", domain:1, obj:"1.3", diff:"medium", q:"Compared with a virtual machine, a primary benefit of a container for deploying a data pipeline is that it:", options:["Starts faster and uses fewer resources by sharing the host kernel","Includes a full separate operating system","Cannot be moved between environments","Requires no configuration at all"], answer:0, explain:"A container <strong>Starts faster and uses fewer resources by sharing the host kernel</strong>, avoiding the overhead of a full guest OS that a VM carries.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Includes a full separate operating system</b>: that describes a virtual machine, not a container.</span><span class='qd'><b>Cannot be moved between environments</b>: containers are highly portable, which is a major advantage.</span><span class='qd'><b>Requires no configuration at all</b>: containers still require configuration such as images and environment variables.</span>" },
{ id:"D1-074", domain:1, obj:"1.3", diff:"easy", q:"Which is an example of a major public cloud provider an analyst might use for storage and compute?", options:["Microsoft Excel","Amazon Web Services (AWS)","Apache Spark","DBeaver"], answer:1, explain:"<strong>Amazon Web Services (AWS)</strong> is a major public cloud provider offering storage, compute, databases, and analytics services.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Microsoft Excel</b>: Excel is a spreadsheet application, not a cloud platform.</span><span class='qd'><b>Apache Spark</b>: Spark is a distributed processing engine, not a cloud provider.</span><span class='qd'><b>DBeaver</b>: DBeaver is a database client tool, not a cloud provider.</span>" },
{ id:"D1-075", domain:1, obj:"1.3", diff:"medium", q:"An analytics team wants storage that costs the least and is acceptable for data retrieved only a few times a year, tolerating minutes-to-hours retrieval delay. Which tier fits?", options:["Hot/standard storage","Block storage for a live database","Cold/archive storage","In-memory cache"], answer:2, explain:"<strong>Cold/archive storage</strong> offers the lowest cost for rarely accessed data and accepts slower retrieval, matching data fetched only a few times a year.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Hot/standard storage</b>: hot storage is optimized for frequent access at higher cost, which is unnecessary here.</span><span class='qd'><b>Block storage for a live database</b>: block storage for a live database is high-performance and costly, not for rare archival access.</span><span class='qd'><b>In-memory cache</b>: an in-memory cache is the most expensive, fastest tier, the opposite of low-cost archival.</span>" },
{ id:"D1-076", domain:1, obj:"1.3", diff:"hard", q:"A company must keep customer data within a specific country's borders to meet legal requirements when choosing cloud infrastructure. The provider feature that addresses this is:", options:["Auto-scaling","Object versioning","Container orchestration","Region/data residency selection"], answer:3, explain:"<strong>Region/data residency selection</strong> lets the customer pin data to a specific geographic region, satisfying legal requirements to keep data within a country's borders.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Auto-scaling</b>: auto-scaling adjusts capacity and does not control where data physically resides.</span><span class='qd'><b>Container orchestration</b>: orchestration manages containers and is unrelated to geographic data placement.</span><span class='qd'><b>Object versioning</b>: versioning keeps multiple copies of an object but does not enforce its location.</span>" },
{ id:"D1-077", domain:1, obj:"1.3", diff:"medium", q:"Local storage attached directly inside a single server is BEST characterized by which trade-off compared to shared network storage?", options:["Lower latency but not easily shared across multiple servers","Higher latency but unlimited capacity","Always cheaper and infinitely scalable","Accessible only over the public internet"], answer:0, explain:"Local storage offers <strong>Lower latency but not easily shared across multiple servers</strong> because it is physically attached to one host and not exposed over the network.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Higher latency but unlimited capacity</b>: local storage actually has lower latency and limited, fixed capacity.</span><span class='qd'><b>Always cheaper and infinitely scalable</b>: local storage is capacity-limited and not infinitely scalable.</span><span class='qd'><b>Accessible only over the public internet</b>: local storage is directly attached, not internet-accessed.</span>" },
{ id:"D1-078", domain:1, obj:"1.3", diff:"easy", q:"What does a container IMAGE represent?", options:["A running instance of a container","A read-only template containing the app and its dependencies","A physical server","A network firewall rule"], answer:1, explain:"A container image is <strong>A read-only template containing the app and its dependencies</strong> from which running containers are instantiated.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A running instance of a container</b>: a running instance is the container itself, created from the image, not the image.</span><span class='qd'><b>A physical server</b>: an image is software, not hardware.</span><span class='qd'><b>A network firewall rule</b>: a firewall rule controls traffic and is unrelated to a container template.</span>" },
{ id:"D1-079", domain:1, obj:"1.4", diff:"easy", q:"Which programming language is widely used for data analysis and features the pandas library for working with tabular data?", options:["R","Scala","Python","SAS"], answer:2, explain:"<strong>Python</strong> is a general-purpose language popular for data analysis, and pandas is its primary library for manipulating tabular DataFrames.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>R</b>: R is also used for analysis but pandas is a Python library, not an R package.</span><span class='qd'><b>Scala</b>: Scala is used with Spark for big data but is not the home of pandas.</span><span class='qd'><b>SAS</b>: SAS is a proprietary analytics suite and does not use the pandas library.</span>" },
{ id:"D1-080", domain:1, obj:"1.4", diff:"easy", q:"Which language was created primarily for statistical computing and graphics and uses the tidyverse collection of packages?", options:["Python","SQL","Java","R"], answer:3, explain:"<strong>R</strong> was designed for statistical computing and graphics, and the tidyverse is a popular collection of R packages for data science.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Python</b>: Python is general-purpose and uses pandas, not the tidyverse.</span><span class='qd'><b>Java</b>: Java is a general-purpose language not centered on statistical computing or the tidyverse.</span><span class='qd'><b>SQL</b>: SQL queries databases and is not a statistical programming language with the tidyverse.</span>" },
{ id:"D1-081", domain:1, obj:"1.4", diff:"medium", q:"An analyst needs to retrieve, filter, and aggregate rows directly from a relational database. Which language is purpose-built for this?", options:["SQL","HTML","CSS","Bash"], answer:0, explain:"<strong>SQL</strong> (Structured Query Language) is purpose-built to query, filter, join, and aggregate data in relational databases.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>HTML</b>: HTML structures web page content and cannot query a database.</span><span class='qd'><b>CSS</b>: CSS styles web pages and has no data-querying capability.</span><span class='qd'><b>Bash</b>: Bash scripts the shell and is not a relational query language.</span>" },
{ id:"D1-082", domain:1, obj:"1.4", diff:"medium", q:"A data scientist wants an interactive document mixing live code, output, charts, and explanatory text in one shareable file. Which tool BEST provides this?", options:["A static .txt file","A Jupyter notebook","A firewall console","A block storage volume"], answer:1, explain:"<strong>A Jupyter notebook</strong> combines live executable code, its output, visualizations, and narrative text in a single interactive, shareable document.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A static .txt file</b>: a plain text file cannot execute code or render charts.</span><span class='qd'><b>A firewall console</b>: a firewall console manages network rules, not interactive analysis.</span><span class='qd'><b>A block storage volume</b>: block storage holds data but is not an interactive coding environment.</span>" },
{ id:"D1-083", domain:1, obj:"1.4", diff:"easy", q:"Which of the following is a popular business intelligence (BI) visualization platform?", options:["Linux","Python","Tableau","TCP/IP"], answer:2, explain:"<strong>Tableau</strong> is a leading BI platform for building interactive dashboards and visualizations from data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Python</b>: Python is a programming language, not a packaged BI dashboard platform.</span><span class='qd'><b>Linux</b>: Linux is an operating system, not a BI tool.</span><span class='qd'><b>TCP/IP</b>: TCP/IP is a networking protocol suite, unrelated to BI.</span>" },
{ id:"D1-084", domain:1, obj:"1.4", diff:"medium", q:"An organization in the Microsoft ecosystem wants a BI tool that integrates tightly with Excel and Azure for dashboards. Which tool is the BEST fit?", options:["Anaconda","R Studio","DBeaver","Power BI"], answer:3, explain:"<strong>Power BI</strong> is Microsoft's BI platform that integrates tightly with Excel and Azure for building reports and dashboards.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>R Studio</b>: R Studio is an IDE for the R language, not a Microsoft BI dashboard tool.</span><span class='qd'><b>DBeaver</b>: DBeaver is a database client, not a BI visualization platform.</span><span class='qd'><b>Anaconda</b>: Anaconda is a Python/R distribution and package manager, not a BI tool.</span>" },
{ id:"D1-085", domain:1, obj:"1.4", diff:"medium", q:"A team uses a database management tool to connect to SQL Server, write queries, and manage objects through a graphical interface. Which tool is purpose-built for SQL Server?", options:["SQL Server Management Studio (SSMS)","Tableau","pandas","Kubernetes"], answer:0, explain:"<strong>SQL Server Management Studio (SSMS)</strong> is Microsoft's dedicated graphical tool for connecting to, querying, and administering SQL Server.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Tableau</b>: Tableau is a visualization tool, not a SQL Server administration client.</span><span class='qd'><b>pandas</b>: pandas is a Python library for data manipulation, not a DBMS management tool.</span><span class='qd'><b>Kubernetes</b>: Kubernetes orchestrates containers and does not manage SQL Server objects.</span>" },
{ id:"D1-086", domain:1, obj:"1.4", diff:"hard", q:"An analyst must connect to many different database engines (PostgreSQL, MySQL, Oracle) from one cross-platform GUI client. Which tool is designed for this multi-database use?", options:["MongoDB Compass","DBeaver","SSMS","Power BI"], answer:1, explain:"<strong>DBeaver</strong> is a universal, cross-platform database client that connects to many engines such as PostgreSQL, MySQL, and Oracle from a single GUI.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>MongoDB Compass</b>: Compass is specific to MongoDB and does not manage relational engines like Oracle.</span><span class='qd'><b>SSMS</b>: SSMS is tailored to Microsoft SQL Server, not broad multi-engine access.</span><span class='qd'><b>Power BI</b>: Power BI is a BI visualization tool, not a general multi-database administration client.</span>" },
{ id:"D1-087", domain:1, obj:"1.4", diff:"medium", q:"Which tool would an analyst use specifically to browse and query collections in a MongoDB (document) database through a GUI?", options:["Toad","MySQL Workbench","MongoDB Compass","Looker"], answer:2, explain:"<strong>MongoDB Compass</strong> is the official GUI for exploring and querying MongoDB document collections.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>MySQL Workbench</b>: MySQL Workbench is built for the relational MySQL engine, not MongoDB documents.</span><span class='qd'><b>Toad</b>: Toad is a tool family for relational databases like Oracle, not MongoDB.</span><span class='qd'><b>Looker</b>: Looker is a BI/analytics platform, not a MongoDB collection browser.</span>" },
{ id:"D1-088", domain:1, obj:"1.4", diff:"easy", q:"Which of the following is a Python distribution and package/environment manager popular in data science?", options:["SMB","Tableau","NFS","Anaconda"], answer:3, explain:"<strong>Anaconda</strong> is a popular distribution that bundles Python/R plus data-science packages and a package/environment manager (conda).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Tableau</b>: Tableau is a BI visualization tool, not a Python distribution.</span><span class='qd'><b>NFS</b>: NFS is a network file-sharing protocol, unrelated to Python packaging.</span><span class='qd'><b>SMB</b>: SMB is a file-sharing protocol, not a data-science package manager.</span>" },
{ id:"D1-089", domain:1, obj:"1.4", diff:"medium", q:"An IDE (integrated development environment) is valuable to a data analyst primarily because it:", options:["Combines code editing, debugging, and execution in one environment","Replaces the database server","Encrypts all network traffic","Stores data as objects"], answer:0, explain:"An IDE <strong>Combines code editing, debugging, and execution in one environment</strong>, streamlining the analyst's workflow for writing and testing code.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Replaces the database server</b>: an IDE is a development tool, not a database server.</span><span class='qd'><b>Encrypts all network traffic</b>: traffic encryption is a network function, not the role of an IDE.</span><span class='qd'><b>Stores data as objects</b>: object storage is an infrastructure service, not an IDE feature.</span>" },
{ id:"D1-090", domain:1, obj:"1.4", diff:"hard", q:"A team processes terabytes of data across a cluster and writes jobs in a JVM language tightly integrated with Apache Spark. Which language is the BEST fit?", options:["SQL","Scala","HTML","CSS"], answer:1, explain:"<strong>Scala</strong> runs on the JVM and is the language Apache Spark is written in, making it a natural fit for large-scale distributed processing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SQL</b>: SQL queries data but is not a general JVM language for writing Spark cluster jobs.</span><span class='qd'><b>HTML</b>: HTML is a markup language for web pages, not distributed data processing.</span><span class='qd'><b>CSS</b>: CSS styles web pages and cannot process data on a cluster.</span>" },
{ id:"D1-091", domain:1, obj:"1.4", diff:"medium", q:"Which statement BEST describes the difference between a programming language like Python and a BI tool like Tableau for analysis?", options:["They are identical in function","Tableau is only for writing SQL","Python offers flexible custom coding while Tableau provides drag-and-drop visualization","Python cannot read data files"], answer:2, explain:"The key difference is that <strong>Python offers flexible custom coding while Tableau provides drag-and-drop visualization</strong>, suiting different skill levels and tasks.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>They are identical in function</b>: a general-purpose language and a visualization tool serve different purposes.</span><span class='qd'><b>Tableau is only for writing SQL</b>: Tableau focuses on visualization and can connect to data without users writing raw SQL.</span><span class='qd'><b>Python cannot read data files</b>: Python reads many file formats through libraries like pandas.</span>" },
{ id:"D1-092", domain:1, obj:"1.4", diff:"medium", q:"Which tool is a graphical client developed specifically for designing, querying, and administering MySQL databases?", options:["RStudio","MongoDB Compass","Power BI","MySQL Workbench"], answer:3, explain:"<strong>MySQL Workbench</strong> is the official graphical tool for designing, querying, and administering MySQL databases.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>MongoDB Compass</b>: Compass is for MongoDB document databases, not MySQL.</span><span class='qd'><b>Power BI</b>: Power BI is a BI visualization platform, not a MySQL administration client.</span><span class='qd'><b>RStudio</b>: RStudio is an IDE for the R language, not a MySQL management tool.</span>" },
{ id:"D1-093", domain:1, obj:"1.5", diff:"easy", q:"A model that can produce new text, images, or code based on patterns learned from large datasets is an example of:", options:["Generative AI","A relational database","A firewall","A pivot table"], answer:0, explain:"<strong>Generative AI</strong> creates new content such as text, images, or code by learning patterns from large training datasets.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A relational database</b>: a relational database stores and retrieves structured data; it does not generate new content.</span><span class='qd'><b>A firewall</b>: a firewall filters network traffic and creates no content.</span><span class='qd'><b>A pivot table</b>: a pivot table summarizes existing data rather than generating new content.</span>" },
{ id:"D1-094", domain:1, obj:"1.5", diff:"medium", q:"A large language model (LLM) is BEST described as a model that:", options:["Stores data in rows and columns","Is trained on vast text to understand and generate human-like language","Encrypts files at rest","Orchestrates containers"], answer:1, explain:"An LLM <strong>Is trained on vast text to understand and generate human-like language</strong>, predicting likely sequences of words to produce coherent responses.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Stores data in rows and columns</b>: that describes a relational database, not a language model.</span><span class='qd'><b>Encrypts files at rest</b>: encryption is a security function, not what an LLM does.</span><span class='qd'><b>Orchestrates containers</b>: container orchestration is an infrastructure task unrelated to language modeling.</span>" },
{ id:"D1-095", domain:1, obj:"1.5", diff:"medium", q:"A large, broadly pre-trained model that organizations adapt to many downstream tasks via fine-tuning or prompting is called a:", options:["Star schema","Pivot table","Foundational model","Surrogate key"], answer:2, explain:"A <strong>Foundational model</strong> is a large model pre-trained on broad data that can be adapted to many tasks through fine-tuning or prompting.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Pivot table</b>: a pivot table summarizes spreadsheet data and is not an AI model.</span><span class='qd'><b>Star schema</b>: a star schema is a data warehouse design, not a model.</span><span class='qd'><b>Surrogate key</b>: a surrogate key is a generated identifier, unrelated to AI models.</span>" },
{ id:"D1-096", domain:1, obj:"1.5", diff:"medium", q:"A technique that uses neural networks with many layers to learn complex patterns from large amounts of data is known as:", options:["Tokenization of credit cards","Normalization","Indexing","Deep learning"], answer:3, explain:"<strong>Deep learning</strong> uses multi-layer neural networks to automatically learn complex patterns from large datasets.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Normalization</b>: normalization is a database design technique to reduce redundancy, not a neural-network method.</span><span class='qd'><b>Indexing</b>: indexing speeds database lookups and is unrelated to neural networks.</span><span class='qd'><b>Tokenization of credit cards</b>: that tokenization replaces sensitive values for security, not a deep-learning method.</span>" },
{ id:"D1-097", domain:1, obj:"1.5", diff:"medium", q:"An application that reads customer support emails and automatically detects their sentiment and intent relies primarily on:", options:["Natural language processing (NLP)","Block storage","A foreign key constraint","RAID redundancy"], answer:0, explain:"<strong>Natural language processing (NLP)</strong> enables software to interpret human language, including detecting sentiment and intent in text such as support emails.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Block storage</b>: block storage holds raw data volumes and performs no language understanding.</span><span class='qd'><b>A foreign key constraint</b>: a foreign key enforces relationships in a database, not text analysis.</span><span class='qd'><b>RAID redundancy</b>: RAID protects against disk failure and does not process language.</span>" },
{ id:"D1-098", domain:1, obj:"1.5", diff:"medium", q:"A company configures software bots to log into systems and automatically copy data between two legacy applications, mimicking human clicks and keystrokes. This is an example of:", options:["Deep learning","Robotic process automation (RPA)","Data normalization","Object storage"], answer:1, explain:"<strong>Robotic process automation (RPA)</strong> uses software bots to automate repetitive, rule-based tasks by mimicking human interactions across applications.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Deep learning</b>: deep learning trains neural networks on data and is not about scripting UI clicks between apps.</span><span class='qd'><b>Data normalization</b>: normalization is a database design technique, not task automation.</span><span class='qd'><b>Object storage</b>: object storage holds data and does not automate workflows.</span>" },
{ id:"D1-099", domain:1, obj:"1.5", diff:"hard", q:"An analyst uses a generative AI assistant to draft SQL but notices it sometimes returns confidently stated but incorrect column names that do not exist. This behavior is BEST described as:", options:["A normalization error","A SQL injection","A hallucination","A referential integrity violation"], answer:2, explain:"<strong>A hallucination</strong> is when a generative AI model produces confident but factually incorrect or fabricated output, such as nonexistent column names.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A SQL injection</b>: SQL injection is a malicious attack inserting code into a query, not a model fabricating output.</span><span class='qd'><b>A normalization error</b>: a normalization error concerns database design, not AI-generated mistakes.</span><span class='qd'><b>A referential integrity violation</b>: that violation involves invalid foreign keys, not fabricated AI text.</span>" },
{ id:"D1-100", domain:1, obj:"1.5", diff:"hard", q:"A data team wants to reduce AI hallucinations by grounding an LLM's answers in the company's own verified documents at query time. Which approach BEST achieves this?", options:["Adding more foreign keys","Increasing the database normalization level","Switching to block storage","Retrieval-augmented generation (RAG)"], answer:3, explain:"<strong>Retrieval-augmented generation (RAG)</strong> supplies an LLM with relevant verified documents at query time so its answers are grounded in trusted source material, reducing hallucinations.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Increasing the database normalization level</b>: normalization improves data design but does not ground an LLM's responses.</span><span class='qd'><b>Switching to block storage</b>: the storage type has no effect on an LLM's factual grounding.</span><span class='qd'><b>Adding more foreign keys</b>: foreign keys enforce relational integrity and do not influence AI output accuracy.</span>" }
);
